import java.io.*;
import java.util.*;

public class Main {
    private static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        Integer nextInt() throws IOException {
            int c;
            do {
                c = readByte();
                if (c == -1) return null;
            } while (c <= ' ');
            boolean neg = false;
            if (c == '-' ) { neg = true; c = readByte(); }
            int val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }

    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        Integer tObj = fs.nextInt();
        if (tObj == null) return; // no input
        int T = tObj;
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            Integer nObj = fs.nextInt();
            if (nObj == null) break; // safety
            int N = nObj;
            int[] s = new int[N];
            int[] e = new int[N];
            long[] c = new long[N];
            for (int i = 0; i < N; i++) {
                s[i] = fs.nextInt();
                e[i] = fs.nextInt();
                c[i] = fs.nextInt();
            }
            // sort by end time
            Integer[] idx = new Integer[N];
            for (int i = 0; i < N; i++) idx[i] = i;
            Arrays.sort(idx, (a, b) -> Integer.compare(e[a], e[b]));
            int[] start = new int[N];
            int[] end = new int[N];
            long[] comp = new long[N];
            for (int i = 0; i < N; i++) {
                start[i] = s[idx[i]];
                end[i] = e[idx[i]];
                comp[i] = c[idx[i]];
            }
            long[] dp = new long[N];
            for (int i = 0; i < N; i++) {
                // binary search for last non‑overlapping interval
                int lo = 0, hi = i - 1, pos = -1;
                while (lo <= hi) {
                    int mid = (lo + hi) >>> 1;
                    if (end[mid] <= start[i]) {
                        pos = mid;
                        lo = mid + 1;
                    } else {
                        hi = mid - 1;
                    }
                }
                long incl = comp[i] + (pos >= 0 ? dp[pos] : 0);
                long excl = i > 0 ? dp[i - 1] : 0;
                dp[i] = Math.max(incl, excl);
            }
            long ans = N == 0 ? 0 : dp[N - 1];
            sb.append(ans);
            if (tc < T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

